class StatefulGestureDetector extends StatefulProperty<StatefulGestureDetector> {
  final void Function() onTap;

  StatefulGestureDetector({this.onTap});
  @override
  Widget build(Widget child) {
    return GestureDetector(
      onTap: () => onTap?.call(),
      // TODO: Add all other GT handlers
      child: child,
    );
  }
}
```

